    KernelCa6k00329Custom op;
    op.Init(x, y, tiling_data.totalLength, tiling_data.tileLength,
            tiling_data.batch, tiling_data.channels,
            tiling_data.spatialSize, tiling_data.eps);
    op.Process();
}
